import numpy as np
from rank_bm25 import BM25Okapi

def _bm25_tokenize(text):
    import re
    return re.findall(r'\b\w\w+\b', text.lower())

def search(query, df, bm25, model, index, top_k=10):
    query_tokens = _bm25_tokenize(query)
    bm25_scores = bm25.get_scores(query_tokens)

    query_vec = model.encode([query]).astype("float32")
    dists, idxs = index.search(query_vec, 1000)

    # RRF params
    k_rrf = 60
    ranks = np.zeros(len(df))

    # BM25 contribution
    sorted_bm25 = np.argsort(bm25_scores)[::-1]
    for r, idx in enumerate(sorted_bm25[:500]):
        ranks[idx] += 1.0 / (k_rrf + r)

    # Semantic contribution
    for r, idx in enumerate(idxs[0][:500]):
        ranks[idx] += 1.0 / (k_rrf + r)

    # Title match boost: if query words in title, boost significantly
    query_lower = query.lower()
    for i, title in enumerate(df['title']):
        if query_lower in title.lower() or title.lower() in query_lower:
            ranks[i] += 0.5

    # Genre boost: simple overlap
    query_genres = [g.strip().lower() for g in query.split() if g.lower() in ['action', 'comedy', 'drama', 'horror', 'sci-fi', 'romance', 'thriller']]
    if query_genres:
        for i, genres in enumerate(df['genres']):
            if any(g in genres.lower() for g in query_genres):
                ranks[i] += 0.2

    # Final selection
    top_indices = np.argsort(ranks)[-top_k:][::-1]
    return df.iloc[top_indices].to_dict("records")
